catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    g_form.clearOptions('sub_category');
    g_form.addOption('sub_category', '', '-- Select Sub-Category --');

    if (!newValue) return;

    var val = newValue.toString().toLowerCase();

    if (val == 'cables') {
        addOptions(['UTP Cable', 'STP Cable', 'Coaxial Cable', 'Fiber Optic Cable']);
    } 
    else if (val.indexOf('repeater') !== -1) {   // ✅ catches repeater / repeaters / REP
        addOptions(['Analog', 'Digital']);
    } 
    else if (val == 'hub') {
        addOptions(['Active', 'Passive']);
    } 
    else if (val == 'switches') {
        addOptions(['SPST', 'SPDT', 'DPST', 'DPDT']);
    }

    function addOptions(options) {
        for (var i = 0; i < options.length; i++) {
            g_form.addOption('sub_category', options[i], options[i]);
        }
    }
}
